import { getData } from './server.js'
import { JJD, JJHE } from '../../../lib/bundle.js'

// Change this constant to adjust the reporting window.
const DAYS_TO_RENDER = 90

const doc = JJD.from(document)
const serviceRows = doc.find('#service-rows')
const incidentGroups = doc.find('#incident-groups')
const activeIncidentHeader = doc.find('#active-incident-header')
const activeIncidentBody = doc.find('#active-incident-body')

const severityLabels = { 0: 'Info', 1: 'Minor', 2: 'Major' }

// getData() is synchronous — data is generated by the fake server module using a
// seeded PRNG, so no network request or async/await is needed here.
initializePage()

function initializePage() {
    try {
        const { services } = getData(DAYS_TO_RENDER)
        doc.find('#days-shown').setText(String(DAYS_TO_RENDER))
        const serviceRecords = buildServiceRecords(services, DAYS_TO_RENDER)
        renderActiveIncident(serviceRecords)
        renderServiceRows(serviceRecords)
        renderIncidentHistory(serviceRecords)
    } catch (error) {
        console.error(error)
        serviceRows
            .empty()
            .addChild(
                JJHE.create('p')
                    .addClass('empty-incidents')
                    .setText('Unable to generate service status data. Check the browser console for details.'),
            )
    }
}

// ─── Data processing (UI-side) ─────────────────────────────────────────────────────
// These functions translate the raw server response into shapes the render
// functions can consume directly. Adding a new SLI to SERVICE_CATALOG in
// server.js flows through automatically — no changes needed here.

/**
 * Convert the raw server response into a list of service records ready to render.
 * This is the “light processing” step owned by the UI:
 *   - Orders dates into a timeline array
 *   - Computes the period average used in the axis label
 *   - Derives the current status label from the latest day’s SLI health
 */
function buildServiceRecords(services, days) {
    const dateRange = buildDateRange(days)
    return Object.entries(services).map(([id, serviceData]) => {
        const primarySli = serviceData.slis.find((sli) => sli.primary)

        // Turn the date-keyed server map into an ordered timeline array.
        const timeline = dateRange.map((date) => {
            const primaryDayData = primarySli.days[date]
            const hasData = primaryDayData != null

            // Gather readings from every SLI for this date (shown in the tooltip).
            const sliValues = serviceData.slis.map((sli) => ({
                metric: sli.metric,
                unit: sli.unit,
                value: sli.days[date]?.value ?? null,
            }))

            return {
                date,
                hasData,
                primaryValue: primaryDayData?.value ?? null,
                sliValues,
                events: hasData ? (primaryDayData.events ?? []) : [],
            }
        })

        const daysWithData = timeline.filter((day) => day.hasData)
        const periodAvg = computePeriodAvg(daysWithData.map((d) => d.primaryValue))
        const { label: statusLabel, cssClass: statusClass } = computeStatusLabel(timeline, primarySli)

        return {
            id,
            name: serviceData.name,
            primarySli,
            sliDefs: serviceData.slis,
            timeline,
            periodAvg,
            daysWithDataCount: daysWithData.length,
            statusLabel,
            statusClass,
        }
    })
}

function buildDateRange(days) {
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    return Array.from({ length: days }, (_, i) => {
        const d = new Date(today)
        d.setDate(today.getDate() - (days - 1 - i))
        return d.toISOString().slice(0, 10)
    })
}

function computePeriodAvg(values) {
    const valid = values.filter((v) => v !== null)
    if (valid.length === 0) return 0
    return valid.reduce((sum, v) => sum + v, 0) / valid.length
}

/**
 * Determine the service status label from the most recent day that has data.
 * The health score drives both the label text and its CSS colour class.
 */
function computeStatusLabel(timeline, primarySli) {
    const latest = [...timeline].reverse().find((day) => day.hasData)
    if (!latest) return { label: 'No Data', cssClass: 'status-no-data' }
    const health = computeSliHealth(latest.primaryValue, primarySli.slo)
    if (health >= 1) return { label: 'Operational', cssClass: 'status-operational' }
    if (health > 0) return { label: 'Degraded Performance', cssClass: 'status-degraded' }
    return { label: 'Service Disruption', cssClass: 'status-disruption' }
}

// ─── SLI health calculation ─────────────────────────────────────────────────────
/**
 * Compute the error budget remaining ratio for a raw SLI value against its SLO.
 *
 * Availability-style SLOs (direction: 'above') use:
 *   budget     = 100 - target
 *   degradation = target - value
 *
 * The returned ratio is:
 *   1   => full budget remains (or service is above target)
 *   0   => budget fully exhausted
 *   < 0 => service is in budget debt (breached)
 */
function computeSliHealth(value, slo) {
    if (slo.direction === 'above') {
        const budget = 100 - slo.target
        if (budget <= 0) {
            return value >= slo.target ? 1 : -1
        }

        const degradation = slo.target - value
        if (degradation <= 0) {
            return 1
        }

        return (budget - degradation) / budget
    }

    // For "lower is better" metrics (like latency), map against the allowed
    // headroom between ideal and target as an equivalent error budget.
    const budget = slo.target - slo.ideal
    if (budget <= 0) {
        return value <= slo.target ? 1 : -1
    }

    const degradation = value - slo.target
    if (degradation <= 0) {
        return 1
    }

    return (budget - degradation) / budget
}

// ─── Rendering ────────────────────────────────────────────────────────────────────────────
function renderActiveIncident(serviceRecords) {
    const allIncidents = serviceRecords.flatMap((service) =>
        collectIncidents(service).map((incident) => ({ ...incident, serviceName: service.name })),
    )
    const latestIncident = allIncidents.sort((a, b) => b.date.localeCompare(a.date))[0]

    if (!latestIncident) {
        activeIncidentHeader.setText(`No incidents in the last ${DAYS_TO_RENDER} days`)
        activeIncidentBody
            .empty()
            .addChild(JJHE.create('p').setText('All monitored services stayed stable in this reporting period.'))
        return
    }

    activeIncidentHeader.setText(`${latestIncident.serviceName}: ${latestIncident.description}`)
    activeIncidentBody
        .empty()
        .addChild(
            JJHE.create('p').setText(
                `${severityLabels[latestIncident.severity] ?? 'Info'} incident on ${formatDateShort(latestIncident.date)}.`,
            ),
        )
        .addChild(JJHE.create('p').setText(formatSliValues(latestIncident.sliValues)))
}

function renderServiceRows(serviceRecords) {
    serviceRows.empty()

    serviceRecords.forEach((service) => {
        const row = JJHE.create('article').addClass('status-row')
        const rowHeader = JJHE.create('div').addClass('status-row__header')
        const rowMeta = JJHE.create('div').addClass('status-row__meta')
        const slotStrip = JJHE.create('div').addClass('status-row__slots')
        const rowAxis = JJHE.create('div').addClass('status-row__axis')

        rowMeta.addChild(JJHE.create('p').addClass('service-name').setText(service.name))
        rowHeader
            .addChild(rowMeta)
            .addChild(JJHE.create('p').addClass('service-state', service.statusClass).setText(service.statusLabel))

        service.timeline.forEach((day) => {
            slotStrip.addChild(createDaySlot(service, day))
        })

        rowAxis
            .addChild(JJHE.create('span').setText(`${DAYS_TO_RENDER} days ago`))
            .addChild(JJHE.create('span').setText(formatPeriodLabel(service.periodAvg, service.primarySli)))
            .addChild(JJHE.create('span').setText('Today'))

        row.addChild(rowHeader).addChild(slotStrip).addChild(rowAxis)
        serviceRows.addChild(row)
    })
}

function createDaySlot(service, day) {
    const slotClass = getSlotClass(day.hasData, day.primaryValue, service.primarySli.slo)
    const slot = JJHE.create('div').addClass('status-slot', `status-slot--${slotClass}`)

    const tooltip = JJHE.create('div').addClass('status-slot__tooltip')
    tooltip
        .addChild(JJHE.create('div').addClass('tooltip-date').setText(formatDateShort(day.date)))
        .addChild(createTooltipBody(day))

    slot.addChild(tooltip)
    return slot
}

function createTooltipBody(day) {
    const container = JJHE.create('div').addClass('tooltip-copy')

    if (!day.hasData) {
        return container.addChild(JJHE.create('p').setText('No downtime recorded on this day.'))
    }

    day.sliValues.forEach((sli) => {
        if (sli.value !== null) {
            container.addChild(JJHE.create('p').setText(`${sli.metric}: ${formatSliValue(sli)}`))
        }
    })

    day.events.forEach((event) => {
        container.addChild(JJHE.create('p').addClass('tooltip-event').setText(`⚠ ${event.description}`))
    })

    return container
}

function renderIncidentHistory(serviceRecords) {
    incidentGroups.empty()

    serviceRecords.forEach((service) => {
        const incidents = collectIncidents(service)
        const group = JJHE.create('section').addClass('incident-group')
        group.addChild(JJHE.create('h3').setText(service.name))

        if (incidents.length === 0) {
            group.addChild(JJHE.create('p').addClass('empty-incidents').setText('No incidents in this period.'))
            incidentGroups.addChild(group)
            return
        }

        const list = JJHE.create('ul').addClass('incident-list')
        incidents.forEach((incident) => {
            const item = JJHE.create('li').addClass('incident-item')
            const title = JJHE.create('div').addClass('incident-title')

            title
                .addChild(JJHE.create('span').addClass('incident-date').setText(formatDateShort(incident.date)))
                .addChild(
                    JJHE.create('span')
                        .addClass('incident-severity', `severity-${incident.severity}`)
                        .setText(severityLabels[incident.severity] ?? 'Info'),
                )

            item.addChild(title)
                .addChild(JJHE.create('p').setText(incident.description))
                .addChild(JJHE.create('p').addClass('incident-context').setText(formatSliValues(incident.sliValues)))

            list.addChild(item)
        })

        group.addChild(list)
        incidentGroups.addChild(group)
    })
}

function collectIncidents(service) {
    const incidents = []
    service.timeline.forEach((day) => {
        day.events.forEach((event) => {
            incidents.push({
                date: day.date,
                severity: event.severity,
                description: event.description,
                sliValues: day.sliValues,
            })
        })
    })
    return incidents.sort((a, b) => b.date.localeCompare(a.date))
}

// ─── Color helpers ───────────────────────────────────────────────────────────────────────
/**
 * Map a day's SLI reading to one of three semantic slot states.
 * CSS classes (.status-slot--healthy/--degraded/--breached/--empty) own the actual colours.
 */
function getSlotClass(hasData, value, slo) {
    if (!hasData) return 'empty'
    const health = computeSliHealth(value, slo)
    if (health < 0) return 'breached'
    if (health < 0.5) return 'degraded'
    return 'healthy'
}

// ─── Format helpers ───────────────────────────────────────────────────────────────────────

function formatSliValue(sli) {
    if (sli.value === null) return 'No data'
    if (sli.unit === '%') return `${sli.value.toFixed(2)}%`
    return `${sli.value}${sli.unit}`
}

function formatSliValues(sliValues) {
    return (sliValues ?? [])
        .filter((s) => s.value !== null)
        .map((s) => `${s.metric}: ${formatSliValue(s)}`)
        .join(' · ')
}

function formatDateShort(isoDate) {
    const d = new Date(`${isoDate}T00:00:00Z`)
    return d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric', timeZone: 'UTC' })
}

function formatPeriodLabel(avg, primarySli) {
    if (primarySli.metric === 'availability') return `${avg.toFixed(2)}% uptime`
    return `${avg.toFixed(0)} ${primarySli.unit} avg`
}
